final:
module RefModule (
    input clk,
    input set,
    input rst,
    output reg [31:0] q
);

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
    if (rst)
        q <= 32'b00000000000000000000000000000000;
    else if (set)
        q <= 32'b11111111111111111111111111111111;
end

endmodule
